): RunProjection => ({
  runId: "run-merge",
  conversation: [],
  activities: [],
  summary: null,
  lastActivityAt: null,
  ...overrides,
});

describe("mergeProjectionBundles", () => {
  it("deduplicates and enriches local/native tool rows by stable invocation id", () => {
    const localProjection = createProjection({
      conversation: [
        {
          kind: "tool_call_pending",
          invocationId: "call-1",
          role: null,
          content: null,
          toolName: "send_message_to",
          toolArgs: {},
          toolResult: null,
          toolError: null,
          media: null,
          ts: 10,
        },
      ],
      activities: [
        {
          invocationId: "call-1",
          toolName: "send_message_to",
          type: "tool_call",
          status: "parsed",
          contextText: "tool",
          arguments: {},
          logs: [],
          result: null,
          error: null,
          ts: 10,
          detailLevel: "source_limited",
        },
      ],
