          error: null,
          ts: 2,
          detailLevel: "source_limited",
        },
      ],
    });

    const merged = mergeProjectionBundles("run-merge", localProjection, nativeProjection);

    expect(merged?.conversation.map((entry) => entry.toolName)).toEqual([
