import { CodexFileChangePayloadHelper } from "../items/codex-file-change-payload-helper.js";
import { CodexToolPayloadParser } from "../items/codex-tool-payload-parser.js";
import {
  isCodexDynamicToolItemFamily,
  normalizeCodexItemTypeToken,
  resolveCodexToolItemFamily,
  type CodexToolItemFamily,
} from "../items/codex-tool-item-family.js";

export type CodexThreadHistoryToolStatus = "parsed" | "success" | "error" | "denied";

export interface NormalizedCodexThreadHistoryToolItem {
  family: CodexToolItemFamily;
  invocationId: string;
  hasStableInvocationId: boolean;
  toolName: string;
  toolArgs: Record<string, unknown> | null;
  toolResult: unknown | null;
  toolError: string | null;
  status: CodexThreadHistoryToolStatus;
}

export interface NormalizeCodexThreadHistoryItemInput {
  item: Record<string, unknown>;
  turnIndex: number;
  itemIndex: number;
}

const fileChangePayloadHelper = new CodexFileChangePayloadHelper();
const toolPayloadParser = new CodexToolPayloadParser(fileChangePayloadHelper);

const asObject = (value: unknown): Record<string, unknown> =>
  value && typeof value === "object" && !Array.isArray(value)
    ? (value as Record<string, unknown>)
    : {};

const asArray = (value: unknown): unknown[] | null => (Array.isArray(value) ? value : null);

const asString = (value: unknown): string | null =>
  typeof value === "string" && value.trim().length > 0 ? value.trim() : null;

const hasEntries = (value: Record<string, unknown> | null): value is Record<string, unknown> =>
  Boolean(value && Object.keys(value).length > 0);

const compactRecord = (value: Record<string, unknown>): Record<string, unknown> | null => {
  const next: Record<string, unknown> = {};
  for (const [key, row] of Object.entries(value)) {
    if (row === undefined) {
      continue;
    }
    if (typeof row === "string" && row.trim().length === 0) {
      continue;
    }
    next[key] = row;
  }
  return hasEntries(next) ? next : null;
};

const resolveInvocation = (
  item: Record<string, unknown>,
  turnIndex: number,
  itemIndex: number,
): { invocationId: string; hasStableInvocationId: boolean } => {
  const candidate =
    asString(item.invocationId) ??
    asString(item.invocation_id) ??
    asString(item.callId) ??
    asString(item.call_id) ??
    asString(item.toolCallId) ??
    asString(item.tool_call_id) ??
    asString(item.id);
  if (candidate) {
    return { invocationId: candidate, hasStableInvocationId: true };
  }
  return {
    invocationId: `codex-${turnIndex}-${itemIndex}`,
    hasStableInvocationId: false,
  };
};

const qualifyMcpToolName = (
  item: Record<string, unknown>,
  toolName: string | null,
): string | null => {
  if (!toolName || toolName.includes(".")) {
    return toolName;
  }
  const serverName =
    asString(item.server) ??
    asString(item.serverName) ??
    asString(asObject(item.serverInfo).name);
  return serverName ? `${serverName}.${toolName}` : toolName;
};

const resolveToolName = (
  family: CodexToolItemFamily,
  item: Record<string, unknown>,
): string => {
  if (family === "web_search") {
    return "search_web";
  }
  if (family === "command_execution") {
    return "run_bash";
  }
  if (family === "file_change") {
    return "edit_file";
  }

  const payload = { item };
  const parsedName = toolPayloadParser.resolveToolName(payload);
  const historyName = family === "mcp_tool_call"
    ? qualifyMcpToolName(item, parsedName)
    : parsedName;
  return historyName ?? "tool";
};

const resolveToolArguments = (
  family: CodexToolItemFamily,
  item: Record<string, unknown>,
): Record<string, unknown> | null => {
  const payload = { item };
  if (family === "web_search") {
    return compactRecord(toolPayloadParser.resolveWebSearchArguments(payload));
  }
  if (family === "command_execution") {
    return compactRecord(toolPayloadParser.resolveToolArguments(payload, "run_bash"));
  }
  if (family === "file_change") {
    return fileChangePayloadHelper.resolveArguments(payload);
  }
  return compactRecord(toolPayloadParser.resolveDynamicToolArguments(payload));
};

const hasTextContent = (value: unknown): boolean => {
  if (typeof value === "string") {
    return value.trim().length > 0;
  }
  if (!Array.isArray(value)) {
    return false;
  }
  return value.some((entry) => {
    if (typeof entry === "string") {
      return entry.trim().length > 0;
    }
    const row = asObject(entry);
    return Boolean(
      asString(row.text) ??
        asString(row.content) ??
        asString(row.summary) ??
        asString(row.delta) ??
        asString(row.value),
    );
  });
};

const hasExplicitResult = (item: Record<string, unknown>): boolean =>
  item.result !== undefined ||
  item.output !== undefined ||
  item.aggregatedOutput !== undefined ||
  hasTextContent(item.contentItems) ||
  hasTextContent(item.content);

const isTerminalSuccessStatus = (value: string | null): boolean =>
  value === "success" ||
  value === "completed" ||
  value === "done" ||
  value === "ok";

const resolveStatus = (
  family: CodexToolItemFamily,
  item: Record<string, unknown>,
): CodexThreadHistoryToolStatus => {
  const payload = { item };
  const status = toolPayloadParser.resolveExecutionStatus(payload)?.toLowerCase() ?? null;
  if (status === "declined" || status === "denied") {
    return "denied";
  }
  if (toolPayloadParser.isExecutionFailure(payload) || asString(item.error)) {
    return "error";
  }
  if (
    family === "web_search" ||
    family === "command_execution" ||
    family === "file_change" ||
    isTerminalSuccessStatus(status) ||
    hasExplicitResult(item)
  ) {
    return "success";
  }
  return "parsed";
};

const resolveCommandResult = (item: Record<string, unknown>): Record<string, unknown> | null =>
  compactRecord({
    status: asString(item.status) ?? null,
    output: item.aggregatedOutput ?? item.output ?? null,
    exit_code: item.exitCode ?? item.exit_code ?? null,
  });

const resolveFileChangeResult = (item: Record<string, unknown>): Record<string, unknown> | null =>
  compactRecord({
    status: asString(item.status) ?? null,
    changes: asArray(item.changes) ?? null,
  });

const resolveToolResult = (
  family: CodexToolItemFamily,
  item: Record<string, unknown>,
  status: CodexThreadHistoryToolStatus,
): unknown | null => {
  if (status === "error" || status === "denied" || status === "parsed") {
    return null;
  }
  if (family === "command_execution") {
    return resolveCommandResult(item);
  }
  if (family === "file_change") {
    return resolveFileChangeResult(item);
  }
  if (family === "web_search") {
    return toolPayloadParser.resolveWebSearchResult({ item });
  }
  return toolPayloadParser.resolveToolResult({ item });
};

const resolveToolError = (
  item: Record<string, unknown>,
  status: CodexThreadHistoryToolStatus,
): string | null => {
  if (status !== "error" && status !== "denied") {
    return null;
  }
  return toolPayloadParser.resolveToolError({ item });
};

const debugEnabled = (): boolean =>
  process.env.CODEX_THREAD_HISTORY_DEBUG === "1" ||
  process.env.CODEX_THREAD_EVENT_DEBUG === "1";

const isToolLikeUnsupportedItem = (item: Record<string, unknown>): boolean => {
  const type = normalizeCodexItemTypeToken(item.type) ?? "";
  if (
    type.includes("tool") ||
    type.includes("functioncall") ||
    type.includes("command") ||
    type.includes("websearch") ||
    type.includes("filechange")
  ) {
    return true;
  }
  return Boolean(
    asString(item.tool) ??
      asString(item.tool_name) ??
      asString(item.name) ??
      hasEntries(asObject(item.arguments)),
  );
};

const logUnsupportedToolLikeItem = (
  input: NormalizeCodexThreadHistoryItemInput,
): void => {
  if (!debugEnabled() || !isToolLikeUnsupportedItem(input.item)) {
    return;
  }
  console.warn("[CodexThreadHistoryItemNormalizer] Unsupported tool-like history item", {
    type: asString(input.item.type),
    id: asString(input.item.id),
    name: asString(input.item.name) ?? asString(input.item.tool) ?? asString(input.item.tool_name),
    status: asString(input.item.status),
    turnIndex: input.turnIndex,
    itemIndex: input.itemIndex,
  });
};

export const normalizeCodexThreadHistoryItem = (
  input: NormalizeCodexThreadHistoryItemInput,
): NormalizedCodexThreadHistoryToolItem | null => {
  const family = resolveCodexToolItemFamily(input.item.type);
  if (!family) {
    logUnsupportedToolLikeItem(input);
    return null;
  }

  const invocation = resolveInvocation(input.item, input.turnIndex, input.itemIndex);
  const status = resolveStatus(family, input.item);
  const toolArgs = resolveToolArguments(family, input.item);
  const toolName = resolveToolName(family, input.item);
  return {
    family,
    invocationId: invocation.invocationId,
    hasStableInvocationId: invocation.hasStableInvocationId,
    toolName,
    toolArgs,
    toolResult: resolveToolResult(family, input.item, status),
    toolError: resolveToolError(input.item, status),
    status,
  };
};

export const isCodexThreadHistoryDynamicToolItem = (
  item: Record<string, unknown>,
): boolean => isCodexDynamicToolItemFamily(resolveCodexToolItemFamily(item.type));
import type {
  RunProjection,
  RunProjectionActivityEntry,
  RunProjectionActivityStatus,
  RunProjectionActivityType,
  RunProjectionConversationEntry,
  RunProjectionSourceDetailLevel,
} from "./run-projection-types.js";
import { buildRunProjectionBundle } from "./run-projection-utils.js";

type ProjectionRow = RunProjectionConversationEntry | RunProjectionActivityEntry;

const isNonEmptyString = (value: unknown): value is string =>
  typeof value === "string" && value.trim().length > 0;

const normalizeInvocationId = (value: unknown): string | null =>
  isNonEmptyString(value) ? value.trim() : null;

const isGeneratedInvocationId = (value: string): boolean =>
  /^codex-\d+-\d+$/.test(value) || /^[^:\s]+:\d+$/.test(value);

const resolveStableInvocationId = (row: ProjectionRow): string | null => {
  const invocationId = normalizeInvocationId(row.invocationId);
  if (!invocationId || isGeneratedInvocationId(invocationId)) {
    return null;
  }
  return invocationId;
};

const isToolConversationRow = (row: RunProjectionConversationEntry): boolean =>
  row.kind === "tool_call" ||
  row.kind === "tool_call_pending" ||
  Boolean(row.toolName || row.toolArgs || row.toolResult || row.toolError);

const isToolActivityRow = (row: RunProjectionActivityEntry): boolean =>
  Boolean(row.invocationId && row.toolName);

const exactRowKey = (row: ProjectionRow): string => JSON.stringify(row);

const isNonEmptyRecord = (value: unknown): value is Record<string, unknown> =>
  Boolean(value && typeof value === "object" && !Array.isArray(value) && Object.keys(value).length > 0);

const recordRichness = (value: Record<string, unknown> | null | undefined): number =>
  value ? Object.keys(value).length : 0;

const valueRichness = (value: unknown): number => {
  if (value === null || value === undefined) {
    return 0;
  }
  if (typeof value === "string") {
    return value.trim().length;
  }
  if (Array.isArray(value)) {
    return value.length;
  }
  if (typeof value === "object") {
    return Object.keys(value as Record<string, unknown>).length;
  }
  return 1;
};

const pickString = (primary: string | null | undefined, secondary: string | null | undefined): string | null => {
  const primaryValue = isNonEmptyString(primary) ? primary.trim() : null;
  const secondaryValue = isNonEmptyString(secondary) ? secondary.trim() : null;
  if (!primaryValue) {
    return secondaryValue;
  }
  if (!secondaryValue) {
    return primaryValue;
  }
  if (primaryValue === "tool" && secondaryValue !== "tool") {
    return secondaryValue;
  }
  if (secondaryValue.length > primaryValue.length && primaryValue.length <= 4) {
    return secondaryValue;
  }
  return primaryValue;
};

const pickRecord = (
  primary: Record<string, unknown> | null | undefined,
  secondary: Record<string, unknown> | null | undefined,
): Record<string, unknown> | null => {
  if (!isNonEmptyRecord(primary)) {
    return isNonEmptyRecord(secondary) ? secondary : null;
  }
  if (!isNonEmptyRecord(secondary)) {
    return primary;
  }
  const merged = { ...primary, ...secondary };
  return recordRichness(merged) >= recordRichness(primary) ? merged : primary;
};

const pickValue = <T>(primary: T | null | undefined, secondary: T | null | undefined): T | null => {
  if (valueRichness(primary) === 0) {
    return secondary ?? null;
  }
  if (valueRichness(secondary) === 0) {
    return primary ?? null;
  }
  return valueRichness(secondary) > valueRichness(primary) ? (secondary ?? null) : (primary ?? null);
};

const terminalStatusRank: Record<RunProjectionActivityStatus, number> = {
  parsing: 0,
  parsed: 1,
  "awaiting-approval": 2,
  approved: 3,
  executing: 4,
  success: 5,
  denied: 6,
  error: 7,
};

const pickStatus = (
  primary: RunProjectionActivityStatus,
  secondary: RunProjectionActivityStatus,
): RunProjectionActivityStatus =>
  terminalStatusRank[secondary] > terminalStatusRank[primary] ? secondary : primary;

const activityTypeRank: Record<RunProjectionActivityType, number> = {
  tool_call: 0,
  terminal_command: 1,
  edit_file: 1,
  write_file: 2,
};

const pickActivityType = (
  primary: RunProjectionActivityType,
  secondary: RunProjectionActivityType,
): RunProjectionActivityType =>
  activityTypeRank[secondary] > activityTypeRank[primary] ? secondary : primary;

const pickDetailLevel = (
  primary: RunProjectionSourceDetailLevel | null | undefined,
  secondary: RunProjectionSourceDetailLevel | null | undefined,
): RunProjectionSourceDetailLevel | null =>
  primary === "full" || secondary !== "full" ? (primary ?? secondary ?? null) : secondary;

const pickTimestamp = (
  primary: number | null | undefined,
  secondary: number | null | undefined,
): number | null => {
  const primaryTs = typeof primary === "number" && Number.isFinite(primary) && primary > 0 ? primary : null;
  const secondaryTs = typeof secondary === "number" && Number.isFinite(secondary) && secondary > 0 ? secondary : null;
  if (primaryTs === null) {
    return secondaryTs;
  }
  if (secondaryTs === null) {
    return primaryTs;
  }
  return Math.min(primaryTs, secondaryTs);
};

const mergeLogs = (
  primary: string[] | null | undefined,
  secondary: string[] | null | undefined,
): string[] | null => {
  const merged = [...(primary ?? []), ...(secondary ?? [])].filter(isNonEmptyString);
  return merged.length > 0 ? [...new Set(merged)] : null;
};

const mergeConversationToolRows = (
  primary: RunProjectionConversationEntry,
  secondary: RunProjectionConversationEntry,
): RunProjectionConversationEntry => ({
  ...primary,
  kind: primary.kind === "tool_call" || secondary.kind !== "tool_call" ? primary.kind : secondary.kind,
  invocationId: normalizeInvocationId(primary.invocationId) ?? normalizeInvocationId(secondary.invocationId),
  role: primary.role ?? secondary.role ?? null,
  content: pickString(primary.content, secondary.content),
  toolName: pickString(primary.toolName, secondary.toolName),
  toolArgs: pickRecord(primary.toolArgs, secondary.toolArgs),
  toolResult: pickValue(primary.toolResult, secondary.toolResult),
  toolError: pickString(primary.toolError, secondary.toolError),
  media: pickRecord(primary.media, secondary.media) as Record<string, string[]> | null,
  ts: pickTimestamp(primary.ts, secondary.ts),
});

const mergeActivityRows = (
  primary: RunProjectionActivityEntry,
  secondary: RunProjectionActivityEntry,
): RunProjectionActivityEntry => ({
  ...primary,
  invocationId: normalizeInvocationId(primary.invocationId) ?? normalizeInvocationId(secondary.invocationId) ?? primary.invocationId,
  toolName: pickString(primary.toolName, secondary.toolName) ?? primary.toolName,
  type: pickActivityType(primary.type, secondary.type),
  status: pickStatus(primary.status, secondary.status),
  contextText: pickString(primary.contextText, secondary.contextText) ?? primary.contextText,
  arguments: pickRecord(primary.arguments, secondary.arguments),
  logs: mergeLogs(primary.logs, secondary.logs),
  result: pickValue(primary.result, secondary.result),
  error: pickString(primary.error, secondary.error),
  ts: pickTimestamp(primary.ts, secondary.ts),
  detailLevel: pickDetailLevel(primary.detailLevel, secondary.detailLevel),
});

const mergeProjectionRows = <T extends ProjectionRow>(
  primaryRows: T[],
  secondaryRows: T[],
  isMergeableToolRow: (row: T) => boolean,
  mergeToolRows: (primary: T, secondary: T) => T,
): T[] => {
  const merged: T[] = [];
  const exactRows = new Set<string>();
  const stableToolRows = new Map<string, number>();

  for (const row of [...primaryRows, ...secondaryRows]) {
    const exactKey = exactRowKey(row);
    if (exactRows.has(exactKey)) {
      continue;
    }
    exactRows.add(exactKey);

    const invocationId = isMergeableToolRow(row) ? resolveStableInvocationId(row) : null;
    if (invocationId) {
      const existingIndex = stableToolRows.get(invocationId);
      if (existingIndex !== undefined) {
        merged[existingIndex] = mergeToolRows(merged[existingIndex] as T, row);
        continue;
      }
      stableToolRows.set(invocationId, merged.length);
    }
    merged.push(row);
  }

  return merged;
};

export const mergeProjectionBundles = (
  runId: string,
  primaryProjection: RunProjection | null,
  secondaryProjection: RunProjection | null,
): RunProjection | null => {
  if (!primaryProjection) {
    return secondaryProjection;
  }
  if (!secondaryProjection) {
    return primaryProjection;
  }

  const bundle = buildRunProjectionBundle(
    runId,
    mergeProjectionRows(
      primaryProjection.conversation,
      secondaryProjection.conversation,
      isToolConversationRow,
      mergeConversationToolRows,
    ),
    mergeProjectionRows(
      primaryProjection.activities,
      secondaryProjection.activities,
      isToolActivityRow,
      mergeActivityRows,
    ),
  );

  return {
    ...bundle,
    summary: bundle.summary ?? primaryProjection.summary ?? secondaryProjection.summary,
    lastActivityAt:
      bundle.lastActivityAt ??
      primaryProjection.lastActivityAt ??
      secondaryProjection.lastActivityAt,
  };
};

import { CodexFileChangePayloadHelper } from "./codex-file-change-payload-helper.js";

const asObject = (value: unknown): Record<string, unknown> =>
  value && typeof value === "object" && !Array.isArray(value)
    ? (value as Record<string, unknown>)
    : {};

const asString = (value: unknown): string | null =>
  typeof value === "string" && value.length > 0 ? value : null;

const parseJsonRecord = (value: string): Record<string, unknown> => {
  try {
    const parsed = JSON.parse(value);
    return parsed && typeof parsed === "object" && !Array.isArray(parsed)
      ? (parsed as Record<string, unknown>)
      : {};
  } catch {
    return {};
  }
};

const parseJsonValue = (value: string): { parsed: true; value: unknown } | { parsed: false } => {
  try {
    return {
      parsed: true,
      value: JSON.parse(value),
    };
  } catch {
    return { parsed: false };
  }
};

export class CodexToolPayloadParser {
  constructor(private readonly fileChangePayloadHelper: CodexFileChangePayloadHelper) {}

  public resolveWebSearchMetadata(payload: Record<string, unknown>): Record<string, unknown> {
    const metadata = this.sanitizeRecord(asObject(payload.metadata));
    const argumentsPayload = this.resolveWebSearchArguments(payload);
    const next: Record<string, unknown> = {
      ...metadata,
      tool_name: "search_web",
    };
    if (Object.keys(argumentsPayload).length > 0) {
      next.arguments = argumentsPayload;
    }
    return next;
  }

  public resolveWebSearchArguments(payload: Record<string, unknown>): Record<string, unknown> {
    const item = asObject(payload.item);
    const action = asObject(item.action ?? payload.action);
    const next: Record<string, unknown> = {};

    const query = asString(action.query) ?? asString(item.query) ?? asString(payload.query);
    if (query) {
      next.query = query;
    }

    const actionType = asString(action.type);
    if (actionType && actionType !== "other") {
      next.action_type = actionType;
    }

    const queriesCandidate = action.queries ?? item.queries ?? payload.queries;
    if (Array.isArray(queriesCandidate)) {
      const queries = queriesCandidate
        .filter((entry): entry is string => typeof entry === "string")
        .map((entry) => entry.trim())
        .filter((entry) => entry.length > 0);
      if (queries.length > 0) {
        next.queries = queries;
      }
    }

    return this.sanitizeRecord(next);
  }

  public resolveWebSearchResult(payload: Record<string, unknown>): unknown {
    const item = asObject(payload.item);
    const explicitResult = payload.result ?? item.result ?? payload.output ?? item.output;
    const status = this.resolveExecutionStatus(payload) ?? "completed";
    return this.sanitizeRecord({
      status,
      ...this.resolveWebSearchArguments(payload),
      ...(explicitResult !== undefined ? { result: explicitResult } : {}),
    });
  }

  public resolveWebSearchError(payload: Record<string, unknown>): string {
    const error = this.resolveToolError(payload);
    return error === "Tool execution failed." ? "Web search failed." : error;
  }

  public resolveToolName(
    payload: Record<string, unknown>,
    fallback?: "run_bash" | "edit_file",
  ): string | null {
    const item = asObject(payload.item);
    return (
      asString(payload.tool_name) ??
      asString(payload.tool) ??
      asString(payload.command_name) ??
      asString(item.tool_name) ??
      asString(item.tool) ??
      asString(item.name) ??
      fallback ??
      null
    );
  }

  public resolveToolArguments(
    payload: Record<string, unknown>,
    fallbackToolName: "run_bash" | "edit_file",
  ): Record<string, unknown> {
    const item = asObject(payload.item);
    const explicitArguments = this.sanitizeRecord(
      this.resolveStructuredArguments(payload.arguments, payload.args, payload.input),
    );
    const itemArguments = this.sanitizeRecord(
      this.resolveStructuredArguments(item.arguments, item.args, item.input),
    );
    const mergedArguments: Record<string, unknown> = { ...itemArguments, ...explicitArguments };
    const command = this.resolveCommandValue(payload);
    const fileChangeFields = this.fileChangePayloadHelper.resolveFields(payload);
    const pathValue =
      asString(mergedArguments.path) ??
      asString(payload.path) ??
      asString(item.path) ??
      fileChangeFields.path;
    const patchValue =
      asString(mergedArguments.patch) ??
      asString(mergedArguments.diff) ??
      asString(payload.patch) ??
      asString(payload.diff) ??
      asString(item.patch) ??
      asString(item.diff) ??
      fileChangeFields.patch;

    if (fallbackToolName === "run_bash") {
      const commandValue =
        asString(mergedArguments.command) ?? asString(mergedArguments.cmd) ?? command;
      if (commandValue) {
        mergedArguments.command = commandValue;
      }
      return this.sanitizeRecord(mergedArguments);
    }

    const next: Record<string, unknown> = { ...mergedArguments };
    if (pathValue) {
      next.path = pathValue;
    }
    if (patchValue) {
      next.patch = patchValue;
    }
    return this.sanitizeRecord(next);
  }

  public resolveDynamicToolArguments(payload: Record<string, unknown>): Record<string, unknown> {
    const item = asObject(payload.item);
    const explicitArguments = this.sanitizeRecord(
      this.resolveStructuredArguments(payload.arguments, payload.args, payload.input),
    );
    const itemArguments = this.sanitizeRecord(
      this.resolveStructuredArguments(item.arguments, item.args, item.input),
    );
    return this.sanitizeRecord({ ...itemArguments, ...explicitArguments });
  }

  public resolveToolCallMetadataArguments(
    payload: Record<string, unknown>,
  ): Record<string, unknown> {
    const item = asObject(payload.item);
    const invocation = asObject(payload.invocation);
    const itemInvocation = asObject(item.invocation);
    const msg = asObject(payload.msg);
    const msgInvocation = asObject(msg.invocation);
    const explicitArguments = this.sanitizeRecord(
      this.resolveStructuredArguments(
        payload.arguments,
        payload.args,
        payload.input,
        invocation.arguments,
        invocation.args,
        invocation.input,
        msgInvocation.arguments,
        msgInvocation.args,
        msgInvocation.input,
      ),
    );
    const itemArguments = this.sanitizeRecord(
      this.resolveStructuredArguments(
        item.arguments,
        item.args,
        item.input,
        itemInvocation.arguments,
        itemInvocation.args,
        itemInvocation.input,
      ),
    );
    const mergedArguments: Record<string, unknown> = { ...itemArguments, ...explicitArguments };

    const query = asString(mergedArguments.query) ?? asString(payload.query) ?? asString(item.query);
    if (query) {
      mergedArguments.query = query;
    }

    const queriesCandidate = mergedArguments.queries ?? payload.queries ?? item.queries;
    if (Array.isArray(queriesCandidate)) {
      const queries = queriesCandidate
        .filter((entry): entry is string => typeof entry === "string")
        .map((entry) => entry.trim())
        .filter((entry) => entry.length > 0);
      if (queries.length > 0) {
        mergedArguments.queries = queries;
      }
    }

    return this.sanitizeRecord(mergedArguments);
  }

  public resolveCommandValue(payload: Record<string, unknown>): string | null {
    const item = asObject(payload.item);
    return (
      asString(payload.command) ??
      asString(item.command) ??
      this.resolveCommandActionValue(payload)
    );
  }

  public resolveLogEntry(payload: Record<string, unknown>): string {
    const item = asObject(payload.item);
    return asString(payload.delta) ?? asString(payload.output) ?? asString(item.output) ?? "";
  }

  public resolveToolDecisionReason(payload: Record<string, unknown>): string | null {
    return asString(payload.reason);
  }

  public resolveToolResult(payload: Record<string, unknown>): unknown {
    const item = asObject(payload.item);
    const candidate =
      payload.result ??
      item.result ??
      payload.output ??
      item.output ??
      payload.aggregatedOutput ??
      item.aggregatedOutput;
    if (candidate !== undefined) {
      return candidate;
    }

    const textCandidate = this.resolveToolResultText(payload);
    if (textCandidate) {
      const parsed = parseJsonValue(textCandidate);
      if (parsed.parsed) {
        return parsed.value;
      }
      return textCandidate;
    }

    return { success: !this.isExecutionFailure(payload) };
  }

  public resolveToolError(payload: Record<string, unknown>): string {
    const item = asObject(payload.item);
    const candidate =
      asString(payload.error) ??
      asString(payload.message) ??
      asString(item.error) ??
      asString(item.message);
    if (candidate) {
      return candidate;
    }

    const textCandidate = this.resolveToolResultText(payload);
    if (textCandidate) {
      const parsed = parseJsonValue(textCandidate);
      if (parsed.parsed) {
        const parsedError = this.resolveParsedErrorText(parsed.value);
        if (parsedError) {
          return parsedError;
        }
      }
      return textCandidate;
    }

    const status = (asString(payload.status) ?? asString(item.status))?.toLowerCase();
    if (status === "declined") {
      return "Tool execution denied.";
    }

    return "Tool execution failed.";
  }

  public resolveExecutionStatus(payload: Record<string, unknown>): string | null {
    const item = asObject(payload.item);
    return asString(item.status) ?? asString(payload.status);
  }

  public isExecutionFailure(payload: Record<string, unknown>): boolean {
    const item = asObject(payload.item);
    if (payload.success === false || item.success === false) {
      return true;
    }
    const status = this.resolveExecutionStatus(payload)?.toLowerCase();
    return status === "failed" || status === "error";
  }

  private sanitizeRecord(value: Record<string, unknown>): Record<string, unknown> {
    const next: Record<string, unknown> = {};
    for (const [key, row] of Object.entries(value)) {
      if (typeof row === "string" && row.trim().length === 0) {
        continue;
      }
      if (row !== undefined) {
        next[key] = row;
      }
    }
    return next;
  }

  private asRecord(value: unknown): Record<string, unknown> {
    if (value && typeof value === "object" && !Array.isArray(value)) {
      return value as Record<string, unknown>;
    }
    if (typeof value === "string") {
      const trimmed = value.trim();
      if (!trimmed) {
        return {};
      }
      return parseJsonRecord(trimmed);
    }
    return {};
  }

  private resolveStructuredArguments(...candidates: unknown[]): Record<string, unknown> {
    const merged: Record<string, unknown> = {};
    for (const candidate of candidates) {
      Object.assign(merged, this.asRecord(candidate));
    }
    return merged;
  }

  private collectText(value: unknown): string {
    if (typeof value === "string") {
      return value;
    }
    if (!Array.isArray(value)) {
      return "";
    }

    const chunks: string[] = [];
    for (const entry of value) {
      if (typeof entry === "string") {
        chunks.push(entry);
        continue;
      }
      const row = asObject(entry);
      const text =
        asString(row.text) ??
        asString(row.content) ??
        asString(row.summary) ??
        asString(row.delta) ??
        asString(row.reasoning) ??
        asString(row.value) ??
        null;
      if (text) {
        chunks.push(text);
      }
    }

    return chunks.join("");
  }

  private resolveToolResultText(payload: Record<string, unknown>): string {
    const item = asObject(payload.item);
    const candidate =
      this.collectText(payload.contentItems) ||
      this.collectText(item.contentItems) ||
      this.collectText(payload.content) ||
      this.collectText(item.content);
    return candidate.trim();
  }

  private resolveParsedErrorText(value: unknown): string | null {
    if (typeof value === "string" && value.trim().length > 0) {
      return value;
    }
    const parsed = asObject(value);
    const direct = asString(parsed.error) ?? asString(parsed.message);
    if (direct) {
      return direct;
    }
    const nestedError = asObject(parsed.error);
    return asString(nestedError.message) ?? asString(nestedError.code);
  }

  private resolveCommandActionValue(payload: Record<string, unknown>): string | null {
    const item = asObject(payload.item);
    const actionCandidates = [payload.commandActions, item.commandActions];
    for (const candidate of actionCandidates) {
      if (!Array.isArray(candidate)) {
        continue;
      }
      for (const row of candidate) {
        const action = asObject(row);
        const command =
          asString(action.command) ??
          asString(action.cmd) ??
          asString(action.shell_command) ??
          asString(action.shellCommand);
        if (command) {
          return command;
        }
      }
    }
    return null;
  }
}

