  toolName: string;
  toolArgs: Record<string, unknown> | null;
  toolResult: unknown | null;
  toolError: string | null;
  status: CodexThreadHistoryToolStatus;
}

export interface NormalizeCodexThreadHistoryItemInput {
  item: Record<string, unknown>;
  turnIndex: number;
